import { forwardRef, useRef, useImperativeHandle } from 'react';
import O9Button from '../Button/Button';
import O9IconButton from '../IconButton/IconButton';
import O9Indicator, { type IndicatorVariant, type IndicatorSize } from '../Indicator/Indicator';

export type FabButtonVariant = 'primary' | 'secondary';

export interface O9FabButtonProps {
  variant?: FabButtonVariant;
  icon: string;
  label?: string;
  isDisabled?: boolean;
  isLoading?: boolean;
  indicator?: IndicatorVariant | false;
  indicatorSize?: IndicatorSize;
  zIndex?: number;
  tooltip?: string;
  className?: string;
  onClick?: React.MouseEventHandler<HTMLButtonElement>;
  onFocus?: React.FocusEventHandler<HTMLButtonElement>;
  onBlur?: React.FocusEventHandler<HTMLButtonElement>;
}

export interface O9FabButtonRef {
  focus: () => void;
  buttonElement: HTMLButtonElement | null;
}

const VALID_VARIANTS: readonly FabButtonVariant[] = ['primary', 'secondary'];

const O9FabButton = forwardRef<O9FabButtonRef, O9FabButtonProps>(
  function O9FabButton(
    {
      variant = 'primary',
      icon,
      label,
      isDisabled = false,
      isLoading = false,
      indicator = false,
      indicatorSize = 'lg',
      zIndex,
      tooltip,
      className,
      onClick,
      onFocus,
      onBlur,
    },
    ref,
  ) {
    const btnRef = useRef<HTMLButtonElement>(null);

    useImperativeHandle(ref, () => ({
      focus: () => btnRef.current?.focus(),
      buttonElement: btnRef.current,
    }));

    const safeVariant = VALID_VARIANTS.includes(variant) ? variant : 'primary';
    const isWithLabel = !!label;
    const blocked = isDisabled || isLoading;
    const showIndicator = indicator !== false && !blocked;

    const wrapperClasses = [
      'o9ds-fab-btn',
      `o9ds-fab-btn--${safeVariant}`,
      isWithLabel ? 'o9ds-fab-btn--with-label' : 'o9ds-fab-btn--icon-only',
      isDisabled ? 'is-disabled' : '',
      isLoading ? 'loading' : '',
      className ?? '',
    ]
      .filter(Boolean)
      .join(' ');

    const wrapperStyle: React.CSSProperties | undefined =
      zIndex !== undefined ? { zIndex } : undefined;

    return (
      <div
        className={wrapperClasses}
        style={wrapperStyle}
        aria-busy={isLoading ? true : undefined}
      >
        {isWithLabel ? (
          <O9Button
            ref={btnRef}
            variant={safeVariant}
            size="md"
            icon={icon}
            label={label!}
            isDisabled={isDisabled}
            isLoading={isLoading}
            tooltip={tooltip}
            onClick={onClick}
            onFocus={onFocus}
            onBlur={onBlur}
          />
        ) : (
          <O9IconButton
            ref={btnRef}
            variant={safeVariant}
            size="lg"
            icon={icon}
            tooltip={tooltip ?? ''}
            isDisabled={isDisabled}
            isLoading={isLoading}
            onClick={onClick}
            onFocus={onFocus}
            onBlur={onBlur}
          />
        )}
        {showIndicator && (
          <O9Indicator variant={indicator} size={indicatorSize} />
        )}
      </div>
    );
  },
);

export default O9FabButton;
